"recommended_improvements": [

  {

    "category": "Concurrency",

    "improvement": "Decouple the Event Loop",

    "details": "Ensure heavy processing (LLM calls, heavy I/O) are offloaded to asyncio.to_thread or a dedicated message queue (like Redis/Celery) so the WebSocket server never blocks."

  },

  {

    "category": "Architecture",

    "improvement": "Plugin-Based Decision Engine",

    "details": "Instead of a monolithic Decision Engine, use a plugin architecture where new skills (Telegram alerts, Smart Home, Web Search) can be dynamically loaded."

  },

  {

    "category": "State Management",

    "improvement": "Adopt Zustand or Redux",

    "details": "Migrate away from complex, deeply nested React Contexts to a dedicated state manager to handle high-frequency data (like Hand Tracking coordinates) without causing massive re-renders."

  },

],

"historical_issues_and_fixes": [

  {

    "issue": "Audio Feedback Loop (Jarvis Hearing Itself)",

    "symptoms": "The microphone picked up the system's own TTS output, causing infinite conversational loops and hallucinations.",

    "fix_implemented": "Added strict `isSpeakingRef` state guards in `VoiceContext.tsx` to explicitly pause audio processing while Jarvis is speaking."

  },

  {

    "issue": "MediaPipe Initialization Crashes",

    "symptoms": "HandTracker module frequently failed to load due to missing local assets or Vite bundler pathing errors.",

    "fix_implemented": "Switched MediaPipe to a CDN-based loading approach in `HandTracker.tsx`, ensuring assets are reliably fetched independent of the local build."

  },

  {

    "issue": "Vite Port Instability",

    "symptoms": "Vite would randomly assign new ports if 8080 was briefly occupied, breaking the Tray application's hardcoded dashboard URL.",

    "fix_implemented": "Permanently locked the frontend to port 8080 via `vite.config.ts` and synced `backend/tray.py` to always expect this port."

  },

  {

    "issue": "File Watcher Infinite Loop / Telegram Spam",

    "symptoms": "The file watcher monitored its own log output. When a log was written, it triggered a Telegram alert, which wrote another log, causing a feedback loop.",

    "fix_implemented": "Updated `launcher.py` and watcher configurations to strictly ignore `*.log` files and the application's own output directories."

  },

  {

    "issue": "Dual WebSocket Connection Race Conditions",

    "symptoms": "Multiple UI components attempted to open separate WebSocket connections, duplicating messages and crashing the backend.",

    "fix_implemented": "Refactored the React frontend to use a single, unified WebSocket provider architecture that shares the connection globally."

  },

  {

    "issue": "Voice Activation Latency",

    "symptoms": "Sending all audio to the Python backend for wake-word detection caused unacceptable delays.",

    "fix_implemented": "Created a Hybrid Pipeline: using the browser's Web Speech API for zero-latency burst wake-word detection, while retaining the Python backend for complex/offline transcription."

  },

],

